('ef64d3ba-04a0-5af3-a4f7-f2a1255660f3', 2, 'comptroller_status_verified', 'disqualifying', NULL, 'TX Comptroller Taxable Entity status: active (presumed) (SOS file #?, formed ?, registered agent: ?).', 'tx_comptroller_taxable_entity_search', 'https://comptroller.texas.gov/taxes/franchise/account-status/search', '2026-05-16'),
('1f9b4b20-1bae-559b-a9bd-8fb1b18f3aac', 1, 'owner_age_proxy_rpls_tenure', 'positive', NULL, 'Senior RPLS Freddy A. Gormly (TBPELS license #1918) granted 1977-02-16 → 49yr tenure. TX RPLS requires 4yr college + 4yr supervised survey-in-training + state exam (typically earned at age 28-35); est. owner age ~79.', 'tbpels_rpls_roster', 'https://tbpedownloads.s3-us-west-2.amazonaws.com/rpls_roster.csv', '2026-05-16');
